VALUES
  ('heelevel3-8b44517b-moex-00195', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-111-3082b5f1', 'sub-heelevel3-8b44517b-04', NULL, 'essay', '依戶籍法第 48 條第 1 項規定，戶籍登記之申請，應於事件發生或確定
後 30 日內為之。據此，申請人有依法定期限向戶政事務所辦理戶籍登記
之義務，如申請人不於期限內辦理戶籍登記者，即依同法（舊法）第 79
條之規定處新臺幣 300元以上 900 元以下罰鍰。假設國人某甲於國外結
婚後 6個月，該（新法）第 79條經修法而變更處以新臺幣1000元以上
1500元以下罰鍰，故後法比較前法顯有更重之行政罰。申請人於結婚後
1 年，始回國申請辦理結婚登記。
試問：行政機關應依戶籍法第 79 條之新法或舊法來處罰申請人？並請
申述其理由。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:12+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "310", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('heelevel3-8b44517b-moex-00196', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-111-3082b5f1', 'sub-heelevel3-8b44517b-04', NULL, 'essay', 'A 直轄市都市發展局依行政程序法第 16 條規定，委託某民間開發公司
B 改造該直轄市之某老舊市區。B 公司爰於受委託之權限範圍內與甲下
水道工程公司締結行政契約，約定甲負責清理、淨化該市區淤積之下水
道，而 B則於必要範圍內，依法發給甲各項工程許可及廢棄物清理許可。
準此，甲若依約向 B申請下水道之某工程許可，而 B 拒絕發給時，甲應
提起何種類型之行政訴訟，以為救濟？甲如情況急迫，有聲請暫時權利
保護之必要時，應向 B、A，抑或行政法院聲（申）請那一種類型之暫時
權利保護？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:12+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "310", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('heelevel3-8b44517b-moex-00197', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-111-3082b5f1', 'sub-heelevel3-8b44517b-04', NULL, 'single_choice', '關於行政法法源之敘述，下列何者正確？', '["緊急命令係取代或暫停法律之規範，故其不得作為行政法之法源", "法規命令規範事項雖屬行政機關內部事務，但仍可作為行政法之法源", "由立法院審議通過產生國內法律效力後，係屬行政法之法源", "行政規則在對人民權利有所限制時，才能例外作為行政法法源 31350、31450 32050、32750 32850 33550"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:12+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "310", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('heelevel3-8b44517b-moex-00198', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-111-3082b5f1', 'sub-heelevel3-8b44517b-04', NULL, 'single_choice', '下列何者須有法律或有法律具體明確授權之依據始得為之？', '["補助國旅", "吊銷證照", "執行法律之細節性、技術性事項", "不涉及重大公益之給付行政"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:12+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "310", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('heelevel3-8b44517b-moex-00199', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-111-3082b5f1', 'sub-heelevel3-8b44517b-04', NULL, 'single_choice', '關於訴訟紛爭之解決途徑，下列敘述何者錯誤？', '["政府機關採購物品之履約爭議，得向普通法院提起民事訴訟", "消費者向公營銀行貸款之履約爭議，得向普通法院提起民事訴訟", "不服台灣電力公司計收電費之通知，得向普通法院提起民事訴訟", "申請購買國民住宅，因資格不符而遭拒絕，得向普通法院提起民事訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:12+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "310", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('heelevel3-8b44517b-moex-00200', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-111-3082b5f1', 'sub-heelevel3-8b44517b-04', NULL, 'single_choice', '關於行政組織之敘述，下列何者錯誤？', '["依現行法制，行政院農業委員會農田水利署為行政法人", "依現行法制，國家中山科學研究院為行政法人", "地方自治團體具有公法人之法律地位", "里長雖經選舉，但「里」不具地方自治團體之法律地位"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:12+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "310", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('heelevel3-8b44517b-moex-00201', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-111-3082b5f1', 'sub-heelevel3-8b44517b-04', NULL, 'single_choice', '關於委託行使公權力之概念，下列敘述何者錯誤？', '["受託行使公權力之個人或團體，於委託範圍內，視為行政機關", "委託行使公權力得僅限於私經濟行政", "委託方式得以行政處分或行政契約為之", "行政機關得依法規將其權限之一部分，委託民間團體或個人辦理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:12+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "310", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('heelevel3-8b44517b-moex-00202', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-111-3082b5f1', 'sub-heelevel3-8b44517b-04', NULL, 'single_choice', '稅捐稽徵機關為確認某納稅義務人及其扶養親屬之資料，函請戶政機關提供戶籍資料，性質屬於 下列何者？', '["職務協助", "權限委託", "權限委任", "委辦"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:12+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "310", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('heelevel3-8b44517b-moex-00203', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-111-3082b5f1', 'sub-heelevel3-8b44517b-04', NULL, 'single_choice', '下列何者無公務員懲戒法之適用？', '["私立學校之教師", "具公務員身分之公營事業機構服務人員", "受有俸給之文武職公務員", "公立學校兼任行政工作之教師"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:12+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "310", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('heelevel3-8b44517b-moex-00204', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-111-3082b5f1', 'sub-heelevel3-8b44517b-04', NULL, 'single_choice', '關於公務人員之權利救濟，下列敘述何者正確？', '["辭職若遭拒絕，因屬機關內部之管理措施，公務人員若不服該決定，應向原服務機關提起申訴", "於復審程序或再申訴程序中，公務人員保障暨培訓委員會得依職權或依申請，進行調處", "公務人員提起申訴、再申訴，應向公務人員保障暨培訓委員會為之", "公務人員不服復審之決定，得申請再審議，若對再審議之決定仍不服，得續提行政訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:12+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "310", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL)
